#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding organ-donation-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    preferred_name:string! \
    gender_identity:string! \
    ethnicity:string! \
    preferred_language:string! \
    interpreter_required:string! \
    blood_group:string! \
    gp_name:string! \
    gp_practice:string! \
    referrer_name:string! \
    referrer_role:string! \
    --htmx

cargo loco generate scaffold assessment_donor_type_registration \
    assessment:references \
    donor_type:string! \
    registered_donor:string! \
    organ_donor_register_checked:string! \
    advance_directive:string! \
    advance_directive_details:text! \
    organs_offered:text! \
    relationship_to_recipient:string! \
    cause_of_death:string! \
    cause_of_death_details:text! \
    time_of_death:ts \
    warm_ischaemia_minutes:int \
    donor_type_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medical_history \
    assessment:references \
    hypertension:string! \
    hypertension_duration_years:int \
    diabetes:string! \
    diabetes_type:string! \
    diabetes_duration_years:int \
    malignancy_history:string! \
    malignancy_details:text! \
    malignancy_remission_years:int \
    autoimmune_disease:string! \
    autoimmune_details:text! \
    smoking:string! \
    smoking_pack_years:int \
    alcohol:string! \
    iv_drug_use:string! \
    previous_surgery:string! \
    previous_surgery_details:text! \
    medical_history_notes:text! \
    --htmx

cargo loco generate scaffold assessment_organ_function \
    assessment:references \
    serum_creatinine:double \
    egfr:double \
    proteinuria:string! \
    renal_ultrasound_normal:string! \
    renal_ultrasound_findings:text! \
    alt:double \
    ast:double \
    bilirubin:double \
    albumin:double \
    inr:double \
    liver_steatosis:string! \
    ecg_normal:string! \
    ecg_findings:text! \
    echo_performed:string! \
    lvef:double \
    echo_findings:text! \
    troponin:double \
    pao2:double \
    fio2:double \
    pf_ratio:double \
    chest_xray_normal:string! \
    chest_xray_findings:text! \
    bronchoscopy_performed:string! \
    bronchoscopy_findings:text! \
    organ_function_notes:text! \
    --htmx

cargo loco generate scaffold assessment_infectious_disease \
    assessment:references \
    hiv_status:string! \
    hepatitis_b_surface_antigen:string! \
    hepatitis_b_core_antibody:string! \
    hepatitis_c_antibody:string! \
    hepatitis_c_nat:string! \
    cmv_status:string! \
    ebv_status:string! \
    syphilis_screen:string! \
    htlv_status:string! \
    toxoplasma_status:string! \
    tuberculosis_screen:string! \
    mrsa_screen:string! \
    blood_cultures_taken:string! \
    blood_culture_result:string! \
    blood_culture_organism:text! \
    active_infection:string! \
    active_infection_details:text! \
    infectious_disease_notes:text! \
    --htmx

cargo loco generate scaffold assessment_immunological \
    assessment:references \
    hla_typing_completed:string! \
    hla_a:text! \
    hla_b:text! \
    hla_dr:text! \
    hla_dq:text! \
    crossmatch_performed:string! \
    crossmatch_result:string! \
    pra_percentage:double \
    donor_specific_antibodies:string! \
    donor_specific_antibodies_details:text! \
    abo_compatibility:string! \
    immunological_notes:text! \
    --htmx

cargo loco generate scaffold assessment_surgical \
    assessment:references \
    abdominal_anatomy_normal:string! \
    abdominal_anatomy_findings:text! \
    vascular_anatomy_normal:string! \
    vascular_anatomy_findings:text! \
    ct_angiogram_performed:string! \
    ct_angiogram_findings:text! \
    number_of_renal_arteries:string! \
    previous_abdominal_surgery:string! \
    previous_abdominal_surgery_details:text! \
    anaesthetic_risk:string! \
    surgical_fitness:string! \
    surgical_notes:text! \
    --htmx

cargo loco generate scaffold assessment_psychological \
    assessment:references \
    living_donor:string! \
    independent_assessment_completed:string! \
    assessor_name:string! \
    assessor_role:string! \
    voluntary_consent:string! \
    coercion_concerns:string! \
    coercion_details:text! \
    understands_risks:string! \
    understands_alternatives:string! \
    mental_health_history:string! \
    mental_health_details:text! \
    capacity_to_consent:string! \
    support_network_adequate:string! \
    financial_incentive:string! \
    psychological_notes:text! \
    --htmx

cargo loco generate scaffold assessment_ethical_legal \
    assessment:references \
    consent_type:string! \
    consent_obtained:string! \
    consent_date:date \
    next_of_kin_consulted:string! \
    next_of_kin_name:string! \
    next_of_kin_relationship:string! \
    coroner_notified:string! \
    coroner_consent:string! \
    hta_authorisation:string! \
    hta_reference:string! \
    independent_assessor_approved:string! \
    ethics_committee_review:string! \
    legal_notes:text! \
    --htmx

cargo loco generate scaffold assessment_eligibility_allocation \
    assessment:references \
    eligibility:string! \
    expanded_criteria_donor:string! \
    organs_approved:text! \
    organs_declined:text! \
    decline_reason:text! \
    nhsbt_referral_made:string! \
    nhsbt_reference:string! \
    allocation_priority:string! \
    lead_clinician:string! \
    decision_date:date \
    decision_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    eligibility:string! \
    overall_risk_level:string! \
    donor_risk_index:double \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
